    # Initialize the indegree count for each node and a list to store the result
    indegree = {node: 0 for node in graph}
    sorted_nodes = []

    # Calculate the indegree of each node
    for node, dependencies in graph.items():
        for dependency in dependencies:
            indegree[dependency] += 1

    # Initialize a queue with all nodes that have no dependencies (indegree == 0)
    queue = deque([node for node, count in indegree.items() if count == 0])

    while queue:
        current_node = queue.popleft()
        sorted_nodes.append(current_node)

        # Decrease the indegree of each neighbor and add to queue if it becomes zero
        for neighbor in graph[current_node]:
            indegree[neighbor] -= 1
            if indegree[neighbor] == 0:
                queue.append(neighbor)

    # If not all nodes are visited, a cycle exists; otherwise, return the sorted list
    if len(sorted_nodes) != len(graph):
        raise ValueError("Graph has at least one cycle.")
    return sorted_nodes
